import { Consul, ConsulOptions, LookupOptions } from '@byted-service/consul';
export type LookupOpts = Omit<LookupOptions, 'env'> & {
    /**
     * x-tt-env https://bytedance.feishu.cn/wiki/wikcn2L5x9IgQ4iLEdHofSMPVQc#wju8br
     */
    env?: string;
};
export interface FaasFetchOptions {
    /**
     * `Consul` 实例
     */
    consul?: Consul | LookupOpts;
    /**
     * `Consul` 构建参数
     */
    consulOptions?: ConsulOptions;
    /**
     * `consul.lookup()` 参数
     */
    consulLookupOptions?: LookupOpts;
    faas?: {
        /**
         * `Consul` 实例
         */
        consul?: Consul | LookupOpts;
        /**
         * `Consul` 构建参数
         */
        consulOptions?: ConsulOptions;
        /**
         * `consul.lookup()` 参数
         */
        consulLookupOptions?: LookupOpts;
        /**
         * 是否开启 consul 自动发现 faas 服务 ( 线上强烈建议开启 )，默认 true
         */
        enableConsul?: boolean;
        /**
         * 是否沉默，默认 false，可用于关闭 consul 失败时的 warn 日志
         */
        silence?: boolean;
        /**
         * faas 机房，默认环境配置 ( 开发环境一般为 lf )，优先级高于 region，可用于本地开发时，指定 faas 函数
         */
        idc?: string;
        /**
         * faas 区域，默认环境配置 ( 开发环境一般没有 )，可用于本地开发时，指定 faas 函数
         */
        region?: string;
        /** @deprecated use options.faas.consul instead */
        consulClient?: Consul;
        /** @deprecated use options.faas.consulOptions instead */
        consulClientOptions?: ConsulOptions;
    };
    /** @deprecated use options.consul instead */
    consulClient?: Consul;
    /** @deprecated use options.consulOptions instead */
    consulClientOptions?: ConsulOptions;
}
